80	5. Skeleton Code (Self-Contained)
81	`Cargo.toml`
82	[package]
83	name = "gha-isolated"
84	version = "0.1.0"
85	edition = "2021"
86	description = "Unified isolated GitHub Actions runners (VM preferred)"
87	
88	[dependencies]
89	clap = { version = "4.5", features = ["derive"] }
90	serde = { version = "1.0", features = ["derive"] }
91	serde_yaml = "0.9"
92	which = "6.0"
93	sysinfo = "0.30"
94	duct = "0.13"
95	colored = "2"
96	anyhow = "1.0"
97	`src/main.rs`
98	use clap::{Parser, Subcommand};
99	use anyhow::Result;
100	
101	mod platform;
102	mod backend;
103	mod config;
104	mod runner;
105	
106	#[derive(Parser)]
107	#[command(name = "gha-isolated", about = "Isolated GitHub Actions runners with VM preference")]
108	struct Cli {
109	    #[command(subcommand)]
110	    command: Commands,
111	}
112	
113	#[derive(Subcommand)]
114	enum Commands {
115	    /// Initialize configuration for this machine
116	    Init,
117	    /// Start the runner(s)
118	    Start,
119	    /// Stop the runner(s)
120	    Stop,
121	    /// Show current status
122	    Status,
123	    /// Install as a persistent system service
124	    InstallService,
125	}
126	
127	fn main() -> Result<()> {
128	    let cli = Cli::parse();
129	
130	    match cli.command {
131	        Commands::Init => {
132	            println!("Initializing gha-isolated...");
133	            let plat = platform::detect();
134	            let back = backend::select(&plat);
135	            println!("Detected: {} | Best backend: {:?}", plat.os, back);
136	            config::generate(&plat, &back)?;
137	        }
138	        Commands::Start => {
139	            runner::start()?;
140	        }
141	        Commands::Stop => {
142	            runner::stop()?;
143	        }
144	        Commands::Status => {
145	            runner::status()?;
146	        }
147	        Commands::InstallService => {
148	            println!("Service installation not yet implemented");
149	        }
150	    }
151	
152	    Ok(())
153	}
154	`src/platform.rs`
155	use sysinfo::System;
156	
157	#[derive(Debug, Clone)]
158	pub struct Platform {
159	    pub os: String,
160	    pub arch: String,
161	    pub has_kvm: bool,
162	    pub has_tart: bool,
163	}
164	
165	pub fn detect() -> Platform {
166	    let mut sys = System::new_all();
167	    sys.refresh_all();
168	
169	    let os = if cfg!(target_os = "macos") {
170	        "macos".to_string()
171	    } else if cfg!(target_os = "linux") {
172	        "linux".to_string()
173	    } else {
174	        "unknown".to_string()
175	    };
176	
177	    let arch = std::env::consts::ARCH.to_string();
178	
179	    let has_kvm = std::path::Path::new("/dev/kvm").exists();
180	    let has_tart = which::which("tart").is_ok();
181	
182	    Platform { os, arch, has_kvm, has_tart }
183	}
184	`src/backend.rs`
185	use crate::platform::Platform;
186	
187	#[derive(Debug, Clone, PartialEq)]
188	pub enum Backend {
189	    Tart,
190	    Libvirt,
191	    DockerSysbox,
192	    Docker,
193	}
194	
195	pub fn select(plat: &Platform) -> Backend {
196	    if plat.os == "macos" && plat.has_tart {
197	        return Backend::Tart;
198	    }
199	    if plat.os == "linux" && plat.has_kvm {
200	        return Backend::Libvirt;
201	    }
202	    if plat.os == "linux" {
203	        return Backend::DockerSysbox; // assume Sysbox is installed or will be
204	    }
205	    Backend::Docker
206	}
207	`src/config.rs`
208	use crate::platform::Platform;
209	use crate::backend::Backend;
210	use anyhow::Result;
211	
212	pub fn generate(plat: &Platform, backend: &Backend) -> Result<()> {
213	    let config = match backend {
214	        Backend::Tart | Backend::Libvirt => {
215	            // VM backends get per-VM resource limits
216	            format!(
217	                r#"
218	runners:
219	  default:
220	    backend: {}
221	    labels: [self-hosted, {}]
222	    count: 2
223	    resources:
224	      memory: 4G
225	      cpus: 2
226	"#,
227	                if *backend == Backend::Tart { "tart" } else { "libvirt" },
228	                plat.os
229	            )
230	        }
231	        _ => {
232	            // Docker path with resource limits
233	            r#"
234	runners:
235	  default:
236	    backend: docker
237	    labels: [self-hosted, docker]
238	    count: 2
239	    docker:
240	      memory: 4g
241	      cpus: 2
242	      pids_limit: 100
243	"#
244	            .to_string()
245	        }
246	    };
247	
248	    std::fs::write("outrunner.yml", config)?;
249	    println!("Generated outrunner.yml");
250	    Ok(())
251	}
